type CurrencyValue = number | undefined | string;

export const formatToCurrency = (fullValue: CurrencyValue): string => {
  if (typeof fullValue === 'undefined') return `R$ 0,00`;

  const [value, cents] = String(fullValue).replace('-', '').split('.');

  const formattedCents = cents ? cents.padEnd(2, '0') : '00';
  let formattedValue = '';

  for (let i = 0; i < value.length; i += 1) {
    const currentDigit = value[value.length - 1 - i];

    if (i > 0 && i % 3 === 0) {
      formattedValue = `${currentDigit}.${formattedValue}`;
    } else {
      formattedValue = `${currentDigit}${formattedValue}`;
    }
  }

  return `R$ ${Number(fullValue) >= 0 ? '' : '-'}${formattedValue},${formattedCents[0]}${
    formattedCents[1]
  }`;
};

const formatToNumericCurrency = (fullValue: CurrencyValue, decimalPlaces = 2): string => {
  if (typeof fullValue === 'undefined' || fullValue === '0')
    return `0,${'0'.repeat(decimalPlaces)}`;

  const [value, cents] = String(fullValue).replace('-', '').split('.');

  const formattedCents = cents ? cents.padEnd(decimalPlaces, '0') : '0'.repeat(decimalPlaces);
  let formattedValue = '';

  for (let i = 0; i < value.length; i += 1) {
    const currentDigit = value[value.length - 1 - i];

    if (i > 0 && i % 3 === 0) {
      formattedValue = `${currentDigit}.${formattedValue}`;
    } else {
      formattedValue = `${currentDigit}${formattedValue}`;
    }
  }

  return `${formattedValue},${formattedCents.slice(0, decimalPlaces)}`;
};

const removeCurrencyToken = (value: string) => value.replace('R$', '');

const capitalizeEachWord = (value: string): string => {
  if (!value || typeof value !== 'string') return value;
  return value
    .toLowerCase()
    .split(' ')
    .map((word) => word.charAt(0).toUpperCase() + word.slice(1))
    .join(' ');
};

const removeExtraSpaces = (str: string): string => str.replace(/\s+/g, ' ').trim();

const removeLeadingZeros = (number: string): string => {
  return number.replace(/^0+/, '');
};

function groupBy<T, K extends PropertyKey>(
  array: T[],
  iteratee: ((item: T) => K) | keyof T
): Record<K, T[]> {
  return array.reduce((result, item) => {
    const key =
      typeof iteratee === 'function'
        ? (iteratee as (item: T) => K)(item)
        : (item[iteratee] as unknown as K);

    if (!result[key]) {
      result[key] = [];
    }

    result[key].push(item);

    return result;
  }, {} as Record<K, T[]>);
}

export function sanitizeTaxonomy(text: string): string {
  if (!text || typeof text !== 'string') {
    return '';
  }

  return text
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/[^\w\s]/g, '')
    .replace(/\s+/g, '_')
    .replace(/_+/g, '_')
    .replace(/^_/, '')
    .replace(/_$/, '');
}

